/**
 * SOLUÇÃO FINAL: Delegação de Eventos + Lógica de Acordeão
 * Fecha todos os outros itens abertos (irmãos) antes de alternar o item clicado.
 */
document.addEventListener('click', function(event) {
    // Tenta encontrar o cabeçalho do FAQ clicado
    const clickedHeader = event.target.closest('.gsc-accordion-header');

    if (clickedHeader) {
        // Previne o comportamento padrão e a propagação
        event.preventDefault();
        event.stopPropagation();
        
        const currentItem = clickedHeader.closest('.gsc-accordion-item');

        if (currentItem) {
            // Encontra o container principal (o .gsc-accordion)
            const accordionContainer = currentItem.closest('.gsc-accordion');
            
            if (accordionContainer) {
                // 1. Fecha TODOS os outros itens abertos (que não são o item clicado)
                accordionContainer.querySelectorAll('.gsc-accordion-item.open').forEach(itemToClose => {
                    // Garante que não fechemos o item que está prestes a ser clicado
                    if (itemToClose !== currentItem) {
                        itemToClose.classList.remove('open');
                    }
                });
                
                // 2. Alterna (abre/fecha) APENAS o item clicado
                currentItem.classList.toggle('open');
            }
        }
    }
});